Javascript.validate:
var val = Services.getValue(EnterTheAmount.dataBinding);
var err = null;
var maxVal = 999999.99;


if('0.00' != val)
{
	err = validateCurrencyValue(val, maxVal);
	if( null == err )
	{ 	
		var fVal = WPU.formatToTwoDP(val);
		Services.setValue(EnterTheAmount.dataBinding, fVal);
	}
}
return err;

Javascript.miscCode:
function DefaultCurrency816() {}
DefaultCurrency816.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency816.tabIndex = -1;
DefaultCurrency816.maxLength = 1;
DefaultCurrency816.isReadOnly = function(){return true;}
DefaultCurrency816.isTemporary = function(){return true;}
DefaultCurrency816.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency816.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
